* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100%;
  font-family: "Akkurat Mono";
  background: #121212;
  color: #fff;
}

canvas {
  position: absolute;
  top: 0;
  left: 0;
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

a,
p {
  text-decoration: none;
  text-transform: uppercase;
  font-size: 14px;
  font-weight: 300;
  color: #fff;
}

.container {
  position: relative;
  width: 100%;
  height: 100%;
  padding: 2em;
  mix-blend-mode: difference;
  z-index: 2;
}

nav {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  padding: 2em;
  display: flex;
  z-index: 2;
  mix-blend-mode: difference;
}

nav > div {
  flex: 1;
}

.logo a {
  font-family: "PP Editorial Old";
  font-weight: 400;
}

.header {
  position: relative;
  top: 8em;
  margin-bottom: 12em;
}

.hero-img,
.img {
  width: 100%;
  height: 800px;
  padding-bottom: 1em;
  filter: saturate(0);
  overflow: hidden;
}

.copy {
  position: relative;
  margin: 1em 0;
  padding-bottom: 2em;
}

.copy p {
  opacity: 0.75;
  margin-bottom: 2em;
}

/* lenis scroll */
html {
  scroll-behavior: smooth;
}

html.lenis,
html.lenis body {
  height: auto;
}

.lenis.lenis-smooth {
  scroll-behavior: auto !important;
}

.lenis.lenis-smooth [data-lenis-prevent] {
  overscroll-behavior: contain;
}

.lenis.lenis-stopped {
  overflow: hidden;
}

.lenis.lenis-smooth iframe {
  pointer-events: none;
}
